const { S3Client, GetObjectCommand, PutObjectCommand } = require("@aws-sdk/client-s3");
const path = require("path");

const s3 = new S3Client({});

const OUTPUT_BUCKET = process.env.OUTPUT_BUCKET;
const OUTPUT_PREFIX = process.env.OUTPUT_PREFIX || "processed/";

exports.handler = async (event) => {
  if (!event || !event.Records || !Array.isArray(event.Records)) {
    throw new Error("Invalid S3 event payload");
  }

  const results = [];

  for (const record of event.Records) {
    if (!record.s3 || !record.s3.bucket || !record.s3.object) {
      continue;
    }

    const sourceBucket = record.s3.bucket.name;
    const rawKey = record.s3.object.key;
    const sourceKey = decodeURIComponent(rawKey.replace(/\+/g, " "));

    const fileBuffer = await readS3Object(sourceBucket, sourceKey);
    const processedBuffer = await processFile(fileBuffer, sourceKey);

    const originalFilename = path.basename(sourceKey);
    const outputKey = buildOutputKey(originalFilename);

    const targetBucket = OUTPUT_BUCKET || sourceBucket;

    await s3.send(
      new PutObjectCommand({
        Bucket: targetBucket,
        Key: outputKey,
        Body: processedBuffer,
        ContentType: "application/octet-stream",
      })
    );

    results.push({
      sourceBucket,
      sourceKey,
      targetBucket,
      outputKey,
      status: "processed",
    });
  }

  return {
    statusCode: 200,
    body: JSON.stringify({ results }),
  };
};

async function readS3Object(bucket, key) {
  const response = await s3.send(
    new GetObjectCommand({
      Bucket: bucket,
      Key: key,
    })
  );

  return streamToBuffer(response.Body);
}

async function processFile(buffer, sourceKey) {
  const content = buffer.toString("utf-8");
  const processed = [
    `Processed file: ${path.basename(sourceKey)}`,
    `Processed at: ${new Date().toISOString()}`,
    "",
    content.toUpperCase(),
  ].join("\n");

  return Buffer.from(processed, "utf-8");
}

function buildOutputKey(originalFilename) {
  const normalizedPrefix = OUTPUT_PREFIX.endsWith("/") ? OUTPUT_PREFIX : `${OUTPUT_PREFIX}/`;
  return `${normalizedPrefix}${originalFilename}`;
}

async function streamToBuffer(stream) {
  const chunks = [];
  for await (const chunk of stream) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  }
  return Buffer.concat(chunks);
}